  { label: 'Drinks', targetId: 'sec-drinks', icon: IconPlus, color: 'text-cyan-400' },
  { label: 'Add ons', targetId: 'sec-addons', icon: IconPlus, color: 'text-gray-400' },
];

export const Menu: React.FC<MenuProps> = ({ onAddToCart }) => {
  const categories = Array.from(new Set(MENU_ITEMS.map(item => item.category)));
  const scrollRef = useRef<HTMLDivElement>(null);

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
        const offset = 180; 
        const bodyRect = document.body.getBoundingClientRect().top;
        const elementRect = element.getBoundingClientRect().top;
        const elementPosition = elementRect - bodyRect;
        const offsetPosition = elementPosition - offset;

        window.scrollTo({
            top: offsetPosition,
            behavior: 'smooth'
        });
    }
  };

  const getContainerId = (category: string) => {
      if (category === 'Chicken Broast') return 'sec-broast';
      if (category === 'Snacks') return 'sec-snacks';
      if (category.includes('Fries')) return 'sec-fries';
      if (category === 'Drinks') return 'sec-drinks';
      if (category === 'Add-ons') return 'sec-addons';
      return undefined;
  };

  const getSubcategorySectionId = (category: string, subcategory: string) => {
      if (category === 'House of Beef') {
          if (subcategory.includes('Classic')) return 'sec-classic-beef';
          if (subcategory.includes('Premium')) return 'sec-premium-beef';
      }
      if (category === 'House of Chicken') {
           if (subcategory.includes('Zingsters')) return 'sec-zingsters';
           if (subcategory.includes('Flame')) return 'sec-grilled';
      }
      return undefined;
  };

  // Define dynamic styles based on category
  const getCategoryStyles = (category: string) => {
    if (category.includes('Beef')) return { border: 'border-red-500/30', accent: 'text-red-500', bg: 'hover:bg-red-500/10', glow: 'shadow-red-500/20' };
    if (category.includes('Chicken')) return { border: 'border-yellow-500/30', accent: 'text-yellow-500', bg: 'hover:bg-yellow-500/10', glow: 'shadow-yellow-500/20' };
    if (category.includes('Fries')) return { border: 'border-orange-500/30', accent: 'text-orange-500', bg: 'hover:bg-orange-500/10', glow: 'shadow-orange-500/20' };
    return { border: 'border-gray-700/50', accent: 'text-yellow-500', bg: 'hover:bg-yellow-500/5', glow: 'shadow-yellow-500/10' };
  };

  return (
    <section id="menu" className="pb-20 pt-10 scroll-mt-20">
      <div className="container mx-auto px-4 text-center mb-16 reveal">
        <h2 className="font-bebas text-5xl sm:text-7xl text-white tracking-wider leading-none mb-4">
          EXPLORE OUR <span className="text-transparent bg-clip-text bg-gradient-to-r from-red-500 to-yellow-500">LEGENDARY</span> MENU
        </h2>
        <p className="font-cursive text-yellow-500 text-xl sm:text-2xl opacity-90">Juicy, flavorful, and made fresh for you.</p>
      </div>

      {/* Sticky Menu Navigation Bar */}
      <div className="sticky top-[112px] md:top-24 z-40 bg-gray-950/80 backdrop-blur-xl border-y border-white/5 mb-16 py-4">
        <div className="max-w-7xl mx-auto flex items-center gap-4 px-4 overflow-x-auto no-scrollbar scroll-smooth">
            {NAV_ITEMS.map((item, idx) => (
                <button
                    key={idx}
                    onClick={() => scrollToSection(item.targetId)}
                    className="flex flex-col items-center gap-2 min-w-[90px] group transition-all duration-300 hover:-translate-y-1"
                >
                    <div className={`w-12 h-12 rounded-xl border border-white/10 flex items-center justify-center bg-gray-900 group-hover:border-yellow-500/50 group-hover:shadow-[0_0_15px_rgba(245,158,11,0.2)] transition-all`}>
                        <item.icon className={`w-6 h-6 ${item.color}`} />
                    </div>
                    <span className="text-[10px] font-bold text-gray-400 group-hover:text-yellow-500 uppercase tracking-widest transition-colors">
                        {item.label}
                    </span>
                </button>
            ))}
        </div>
      </div>

      <div className="container mx-auto px-4 max-w-7xl">
        <div className="space-y-24">
          {categories.map((category, idx) => {
            const categoryItems = MENU_ITEMS.filter(item => item.category === category);
            const subcategories = Array.from(new Set(categoryItems.map(item => item.subcategory || 'General')));
            const styles = getCategoryStyles(category);
            const containerIdVal = getContainerId(category);

            return (
              <div key={category} id={containerIdVal} className="reveal scroll-mt-32">
                <div className="flex items-center gap-4 mb-10">
                    <div className={`h-1 w-12 rounded-full bg-gradient-to-r from-transparent to-${styles.accent.split('-')[1]}-500`}></div>
                    <h3 className={`text-3xl sm:text-5xl font-bebas tracking-widest uppercase ${styles.accent}`}>
                      {category}
                    </h3>
                    <div className="h-px flex-1 bg-white/5"></div>
                </div>

                {subcategories.map(subcategory => {
                  const items = categoryItems.filter(item => (item.subcategory || 'General') === subcategory);
                  const showSubheader = subcategory !== 'General';
                  const sectionId = !containerIdVal ? getSubcategorySectionId(category, subcategory) : undefined;

                  return (
                    <div key={subcategory} id={sectionId} className="mb-12 last:mb-0 scroll-mt-40">
                      {showSubheader && (
                        <h4 className="text-xl sm:text-2xl font-bold text-white/80 mb-8 flex items-center gap-3">
                          <Star className={`w-5 h-5 ${styles.accent} fill-current`} />
                          {subcategory}
                        </h4>
                      )}

                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {items.map((item) => (
                          <div 
                            key={item.id}
                            onClick={() => onAddToCart(item)}
                            className={`group relative flex flex-col justify-between p-5 rounded-2xl bg-gray-900/40 border ${styles.border} ${styles.bg} transition-all duration-300 cursor-pointer select-none h-full tap-highlight-transparent hover:shadow-2xl ${styles.glow} transform-gpu hover:-translate-y-2`}
                          >
                            {item.isPopular && (
                                <div className="absolute -top-3 -right-2 bg-yellow-500 text-black text-[10px] font-black px-3 py-1 rounded-full shadow-lg z-10 animate-bounce">
                                    POPULAR
                                </div>
                            )}

                            <div className="flex flex-col h-full relative z-10">
                              <h5 className={`font-bebas text-2xl tracking-wide mb-2 transition-colors duration-300 ${styles.accent} group-hover:text-white`}>
                                {item.name}
                              </h5>

                              <p className="text-sm text-gray-400 leading-relaxed mb-6 group-hover:text-gray-200 transition-colors">
                                {item.description}
                              </p>

                              <div className="mt-auto flex justify-between items-center">
                                <div className="flex flex-col">
                                    <span className="text-xs text-gray-500 uppercase tracking-widest font-bold">Price</span>
                                    <span className="text-2xl font-bebas text-white">
                                      {item.price}/-
                                    </span>
                                </div>

                                <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 bg-gray-800 text-white group-hover:bg-yellow-500 group-hover:text-black shadow-lg group-hover:scale-110`}>
                                    <Plus className="w-5 h-5" />
                                </div>
                              </div>
                            </div>

                            {/* Decorative background accent */}
                            <div className={`absolute bottom-0 right-0 w-24 h-24 bg-gradient-to-br from-transparent to-${styles.accent.split('-')[1]}-500/10 rounded-br-2xl -z-0 opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

import React, { useState, useEffect } from 'react';
import { ShoppingCart, UtensilsCrossed, Clock, MapPin } from 'lucide-react';

interface NavbarProps {
  cartCount: number;
  onOpenCart: () => void;
  onNavigate: (view: 'home' | 'deals', hash?: string) => void;
  currentView: 'home' | 'deals';
}

export const Navbar: React.FC<NavbarProps> = ({ cartCount, onOpenCart, onNavigate, currentView }) => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const updateStatus = () => {
      const now = new Date();
      const pakistanTimeStr = now.toLocaleString("en-US", { timeZone: "Asia/Karachi" });
      const pakistanDate = new Date(pakistanTimeStr);
      const hour = pakistanDate.getHours();
      const day = pakistanDate.getDay();
      const openHour = 17;
      let isShopOpen = false;
      let closingTime = (day === 1 || day === 6 || day === 0) ? 4 : 3;

      if (hour < 5) {
        isShopOpen = hour < closingTime;
      } else {
        isShopOpen = hour >= openHour;
      }
      setIsOpen(isShopOpen);
    };

    updateStatus();
    const interval = setInterval(updateStatus, 60000);
    return () => clearInterval(interval);
  }, []);

  const navLinks = [
    { name: 'MENU', href: '#menu', view: 'home' },
    { name: 'DEALS', href: '#', view: 'deals' },
    { name: 'ABOUT', href: '#about', view: 'home' },
    { name: 'CONTACT', href: '#contact', view: 'home' },
  ];

  const handleLinkClick = (e: React.MouseEvent, link: typeof navLinks[0]) => {
      e.preventDefault();
      onNavigate(link.view as 'home' | 'deals', link.href !== '#' ? link.href : undefined);
  };

  return (
    <nav className="sticky top-0 z-50 transition-all duration-300 border-b border-white/5">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-xl -z-10"></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row md:items-center justify-between h-16 md:h-24">

          {/* Brand & Logo */}
          <div className="flex items-center justify-between md:justify-start w-full md:w-auto h-full gap-4">
            <a 
              href="#home" 
              onClick={(e) => { e.preventDefault(); onNavigate('home', '#home'); }}
              className="flex-shrink-0 flex items-center group transition-transform hover:scale-105"
            >
              <img 
                src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/main/Logo.png" 
                alt="Logo" 
                className="h-10 md:h-16 w-auto drop-shadow-[0_0_8px_rgba(255,255,255,0.2)]" 
              />
              <div className="hidden lg:flex flex-col ml-3 border-l border-white/10 pl-3">
                <span className="font-bebas text-2xl tracking-tighter text-white leading-none">MR. BEEF</span>
                <span className="font-cursive text-yellow-500 text-sm animate-sway">Juicy to the last bite!</span>
              </div>
            </a>

            {/* Mobile Actions Container */}
            <div className="flex md:hidden items-center gap-3">
              <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold tracking-tighter border transition-all duration-500 ${isOpen ? 'bg-green-500/20 border-green-500/50 text-green-400 shadow-[0_0_10px_rgba(34,197,94,0.2)]' : 'bg-red-500/20 border-red-500/50 text-red-400'}`}>
                <span className={`w-1.5 h-1.5 rounded-full ${isOpen ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></span>
                {isOpen ? 'OPEN' : 'CLOSED'}
              </div>
              <button onClick={onOpenCart} className="relative p-2 text-white bg-white/5 rounded-lg border border-white/10">
                <ShoppingCart className="w-5 h-5" />
                {cartCount > 0 && (
                  <span className="absolute -top-1.5 -right-1.5 bg-red-600 text-[10px] font-black w-4 h-4 flex items-center justify-center rounded-full border-2 border-black">
                    {cartCount}
                  </span>
                )}
              </button>
            </div>
          </div>

          {/* Desktop Nav Actions */}
          <div className="hidden md:flex items-center gap-8">
            <div className="flex items-center gap-8 border-r border-white/10 pr-8">
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  onClick={(e) => handleLinkClick(e, link)}
                  className={`relative font-bebas text-xl tracking-widest transition-colors duration-300 group ${
                    currentView === 'deals' && link.name === 'DEALS' 
                      ? 'text-yellow-500' 
                      : 'text-gray-400 hover:text-white'
                  }`}
                >
                  {link.name}
                  <span className={`absolute -bottom-1 left-0 h-0.5 bg-red-500 transition-all duration-300 ${currentView === 'deals' && link.name === 'DEALS' ? 'w-full' : 'w-0 group-hover:w-full'}`}></span>
                </a>
              ))}
            </div>

            <div className="flex items-center gap-4">
              <button
                onClick={onOpenCart}
                className="relative group flex items-center gap-3 bg-red-600 hover:bg-red-500 px-6 py-3 rounded-xl font-bold transition-all duration-300 shadow-xl hover:shadow-red-600/40 active:scale-95 overflow-hidden"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-700"></div>
                <ShoppingCart className="w-5 h-5" />
                <span className="tracking-widest font-bebas text-lg">CART</span>
                {cartCount > 0 && (
                  <span className="bg-white text-red-600 text-xs font-black px-2 py-0.5 rounded-full animate-pulse">
                    {cartCount}
                  </span>
                )}
              </button>

              <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border transition-all duration-500 ${isOpen ? 'bg-green-500/10 border-green-500/30 text-green-400 shadow-[0_0_15px_rgba(34,197,94,0.1)]' : 'bg-red-500/10 border-red-500/30 text-red-400'}`}>
                <Clock className="w-4 h-4" />
                <span className="font-bebas text-lg tracking-wider">{isOpen ? 'OPEN NOW' : 'CLOSED'}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Mobile Sub-Navigation - Brighter & Colorful */}
      <div className="md:hidden flex flex-col w-full bg-black/40 border-t border-white/5">
        <div className="flex justify-between items-center px-6 py-3 overflow-x-auto no-scrollbar gap-8">
           {navLinks.map((link) => (
              <a
                  key={link.name}
                  href={link.href}
                  onClick={(e) => handleLinkClick(e, link)}
                  className={`font-bebas text-lg tracking-widest whitespace-nowrap ${currentView === 'deals' && link.name === 'DEALS' ? 'text-yellow-500 shadow-yellow-500/20' : 'text-gray-400'}`}
              >
                  {link.name}
              </a>
           ))}
        </div>
      </div>
    </nav>
  );
