const Reviews = () => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  const reviewImages = Array.from({ length: 12 }, (_, i) => 
    `https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/refs/heads/main/r${i + 1}.png`
  );

  useEffect(() => {
    const scrollContainer = scrollRef.current;
    if (!scrollContainer) return;
    let animationFrameId: number;
    let autoScrollPos = scrollContainer.scrollLeft;
    const step = () => {
      if (!isDragging && scrollContainer) {
        autoScrollPos += 0.8;
        if (autoScrollPos >= scrollContainer.scrollWidth / 2) autoScrollPos = 0;
        scrollContainer.scrollLeft = autoScrollPos;
      }
      animationFrameId = requestAnimationFrame(step);
    };
    animationFrameId = requestAnimationFrame(step);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setStartX(e.pageX - (scrollRef.current?.offsetLeft || 0));
    setScrollLeft(scrollRef.current?.scrollLeft || 0);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    const x = e.pageX - (scrollRef.current?.offsetLeft || 0);
    const walk = (x - startX) * 2;
    if (scrollRef.current) scrollRef.current.scrollLeft = scrollLeft - walk;
  };

  return (
    <section className="py-24 relative overflow-hidden bg-gray-50 border-y border-gray-100">
        <div className="container mx-auto px-4 mb-16 text-center reveal">
            <h2 className="font-bebas text-5xl sm:text-7xl text-gray-900 mb-4">
              WHAT OUR <span className="text-red-600">LEGENDS</span> SAY
            </h2>
            <div className="flex justify-center gap-1">
              {[...Array(5)].map((_, i) => <Star key={i} className="w-8 h-8 text-yellow-500 fill-current" />)}
            </div>
        </div>

        <div className="relative w-full overflow-hidden">
            <div className="absolute left-0 inset-y-0 w-32 bg-gradient-to-r from-gray-50 to-transparent z-10"></div>
            <div className="absolute right-0 inset-y-0 w-32 bg-gradient-to-l from-gray-50 to-transparent z-10"></div>

            <div 
                ref={scrollRef}
                className="flex overflow-x-auto no-scrollbar cursor-grab active:cursor-grabbing items-center py-10" 
                onMouseDown={handleMouseDown}
                onMouseLeave={() => setIsDragging(false)}
                onMouseUp={() => setIsDragging(false)}
                onMouseMove={handleMouseMove}
            >
                {[...reviewImages, ...reviewImages].map((src, idx) => (
                    <div key={idx} className="flex-shrink-0 w-[280px] sm:w-[400px] mx-6 group transition-all duration-500">
                        <div className="bg-white p-2 rounded-[2rem] border border-gray-100 shadow-xl overflow-hidden group-hover:shadow-2xl transition-all">
                             <img src={src} alt="Review" className="w-full h-auto rounded-[1.8rem]" loading="lazy" />
                        </div>
                    </div>
                ))}
            </div>
        </div>
    </section>
  );
};

