          <div className="flex items-center justify-between md:justify-start w-full md:w-auto h-full gap-4">
            <a 
              href="#home" 
              onClick={(e) => { e.preventDefault(); onNavigate('home', '#home'); }}
              className="flex-shrink-0 flex items-center group"
            >
              <img 
                src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/main/Logo.png" 
                alt="Logo" 
                className="h-10 md:h-16 w-auto drop-shadow-sm" 
              />
              <div className="hidden lg:flex flex-col ml-3 border-l border-gray-200 pl-3">
                <span className="font-bebas text-2xl tracking-tighter text-gray-900 leading-none">MR. BEEF</span>
                <span className="font-cursive text-red-600 text-sm">Juicy to the last bite!</span>
              </div>
            </a>

            <div className="flex md:hidden items-center gap-3">
