export const Menu: React.FC<MenuProps> = ({ onAddToCart }) => {
  const categories = Array.from(new Set(MENU_ITEMS.map(item => item.category)));

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
        const offset = 180; 
        const bodyRect = document.body.getBoundingClientRect().top;
        const elementRect = element.getBoundingClientRect().top;
        const elementPosition = elementRect - bodyRect;
        const offsetPosition = elementPosition - offset;

        window.scrollTo({
            top: offsetPosition,
            behavior: 'smooth'
        });
    }
  };

  const getContainerId = (category: string) => {
      if (category === 'Chicken Broast') return 'sec-broast';
      if (category === 'Snacks') return 'sec-snacks';
      if (category.includes('Fries')) return 'sec-fries';
      if (category === 'Drinks') return 'sec-drinks';
      if (category === 'Add-ons') return 'sec-addons';
      return undefined;
  };

  const getSubcategorySectionId = (category: string, subcategory: string) => {
      if (category === 'House of Beef') {
          if (subcategory.includes('Classic')) return 'sec-classic-beef';
          if (subcategory.includes('Premium')) return 'sec-premium-beef';
      }
      if (category === 'House of Chicken') {
           if (subcategory.includes('Zingsters')) return 'sec-zingsters';
           if (subcategory.includes('Flame')) return 'sec-grilled';
      }
      return undefined;
  };

  // Light theme category styles
  const getCategoryStyles = (category: string) => {
    if (category.includes('Beef')) return { border: 'border-red-200', accent: 'text-red-600', iconBg: 'bg-red-50' };
    if (category.includes('Chicken')) return { border: 'border-yellow-200', accent: 'text-yellow-600', iconBg: 'bg-yellow-50' };
    if (category.includes('Fries')) return { border: 'border-orange-200', accent: 'text-orange-600', iconBg: 'bg-orange-50' };
    return { border: 'border-gray-200', accent: 'text-gray-900', iconBg: 'bg-gray-100' };
  };

  return (
    <section id="menu" className="pb-20 pt-10 scroll-mt-20 bg-white">
      <div className="container mx-auto px-4 text-center mb-16 reveal">
        <h2 className="font-bebas text-6xl sm:text-8xl text-gray-900 tracking-wider mb-2">
          EXPLORE OUR <span className="text-red-600">LEGENDARY</span> MENU
        </h2>
        <p className="font-cursive text-yellow-600 text-2xl opacity-90">Juicy, flavorful, and made fresh for you.</p>
      </div>

      {/* Navigation - Brighter Light Style */}
      <div className="sticky top-[112px] md:top-24 z-40 bg-white/90 backdrop-blur-xl border-y border-gray-100 mb-16 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex items-center gap-4 px-4 overflow-x-auto no-scrollbar scroll-smooth">
            {NAV_ITEMS.map((item, idx) => (
                <button
                    key={idx}
                    onClick={() => scrollToSection(item.targetId)}
                    className="flex flex-col items-center gap-2 min-w-[90px] group transition-all duration-300"
                >
                    <div className={`w-12 h-12 rounded-2xl border border-gray-100 flex items-center justify-center bg-gray-50 group-hover:bg-red-600 group-hover:border-red-600 transition-all duration-300 shadow-sm`}>
                        <item.icon className={`w-6 h-6 ${item.color} group-hover:text-white transition-colors`} />
                    </div>
                    <span className="text-[10px] font-black text-gray-400 group-hover:text-red-600 uppercase tracking-widest transition-colors">
                        {item.label}
                    </span>
                </button>
            ))}
        </div>
      </div>

      <div className="container mx-auto px-4 max-w-7xl">
        <div className="space-y-24">
          {categories.map((category) => {
            const categoryItems = MENU_ITEMS.filter(item => item.category === category);
            const subcategories = Array.from(new Set(categoryItems.map(item => item.subcategory || 'General')));
            const styles = getCategoryStyles(category);
            const containerIdVal = getContainerId(category);

            return (
              <div key={category} id={containerIdVal} className="reveal scroll-mt-32">
                <div className="flex items-center gap-4 mb-10">
                    <h3 className={`text-4xl sm:text-6xl font-bebas tracking-tighter uppercase ${styles.accent}`}>
                      {category}
                    </h3>
                    <div className="h-0.5 flex-1 bg-gray-100"></div>
                </div>

                {subcategories.map(subcategory => {
                  const items = categoryItems.filter(item => (item.subcategory || 'General') === subcategory);
                  const showSubheader = subcategory !== 'General';
                  const sectionId = !containerIdVal ? getSubcategorySectionId(category, subcategory) : undefined;

                  return (
                    <div key={subcategory} id={sectionId} className="mb-12 last:mb-0 scroll-mt-40">
                      {showSubheader && (
                        <h4 className="text-xl font-bold text-gray-900 mb-8 flex items-center gap-3">
                          <Star className="w-5 h-5 text-yellow-500 fill-yellow-500" />
                          {subcategory}
                        </h4>
                      )}

                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {items.map((item) => (
                          <div 
                            key={item.id}
                            onClick={() => onAddToCart(item)}
                            className={`group relative flex flex-col p-6 rounded-[2rem] bg-white border border-gray-100 shadow-lg hover:shadow-2xl hover:-translate-y-2 transition-all duration-300 cursor-pointer tap-highlight-transparent active:scale-95`}
                          >
                            {item.isPopular && (
                                <div className="absolute -top-3 left-6 bg-red-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full shadow-lg z-10 tracking-widest">
                                    TOP SELLER
                                </div>
                            )}

                            <div className="flex flex-col h-full">
                              <h5 className="font-bebas text-3xl tracking-tight text-gray-900 mb-2 group-hover:text-red-600 transition-colors">
                                {item.name}
                              </h5>

                              <p className="text-sm text-gray-500 leading-relaxed mb-8 flex-grow">
                                {item.description}
                              </p>

                              <div className="flex justify-between items-center pt-4 border-t border-gray-50">
                                <div className="flex flex-col">
                                    <span className="text-[10px] text-gray-400 uppercase font-bold tracking-widest">Starting from</span>
                                    <span className="text-3xl font-bebas text-gray-900">
                                      {item.price}/-
                                    </span>
                                </div>

                                <div className="w-12 h-12 rounded-2xl bg-gray-50 text-gray-900 flex items-center justify-center group-hover:bg-red-600 group-hover:text-white transition-all shadow-sm">
                                    <Plus className="w-6 h-6" />
                                </div>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

import React, { useState } from 'react';
import { X, Trash2, Plus, Minus, MessageCircle, MapPin, Phone, User, FileText, Bike, ShoppingBag, AlertCircle } from 'lucide-react';
import { CartItem } from '../types';

interface CartProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (id: string) => void;
  onUpdateQuantity: (id: string, delta: number) => void;
}

export const Cart: React.FC<CartProps> = ({ 
  isOpen, 
  onClose, 
  items, 
  onRemove, 
  onUpdateQuantity 
}) => {
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [instructions, setInstructions] = useState('');
  const [orderType, setOrderType] = useState<'delivery' | 'takeaway'>('delivery');
  const [errors, setErrors] = useState<{name?: boolean; phone?: boolean; address?: boolean}>({});

  const totalAmount = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = items.reduce((sum, item) => sum + item.quantity, 0);

  const validateForm = () => {
    const newErrors: {name?: boolean; phone?: boolean; address?: boolean} = {};
    let isValid = true;

    if (!customerName.trim()) {
      newErrors.name = true;
      isValid = false;
    }
    if (!customerPhone.trim()) {
      newErrors.phone = true;
      isValid = false;
    }
    if (orderType === 'delivery' && !customerAddress.trim()) {
      newErrors.address = true;
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleWhatsAppOrder = () => {
    if (items.length === 0) return;

    if (!validateForm()) {
        return;
    }

    const orderTypeLabel = orderType === 'delivery' ? 'Home Delivery' : 'Takeaway';
    let message = `*New Order from Website (${orderTypeLabel})*\n\n`;

    message += `*Name:* ${customerName}\n`;
    message += `*Phone:* ${customerPhone}\n`;
    if (orderType === 'delivery') {
        message += `*Address:* ${customerAddress}\n`;
    }
    if (instructions) message += `*Instructions:* ${instructions}\n`;
    message += `\n------------------\n`;

    items.forEach(item => {
      message += `- ${item.name} (x${item.quantity}): ${item.price * item.quantity}/-\n`;
      if (item.customDetails) {
          message += `  ${item.customDetails.replace(/\n/g, '\n  ')}\n`;
      }
    });
    message += `\n*Total Amount: ${totalAmount}/-*`;
    message += `\n\nPlease confirm my order.`;

    const phoneNumber = '923240460398';
    const encodedMessage = encodeURIComponent(message);
    const url = `https://wa.me/${phoneNumber}?text=${encodedMessage}`;

    window.open(url, '_blank');
  };

  return (
    <>
      <div 
        className={`fixed inset-0 bg-black/40 z-[60] backdrop-blur-sm transition-opacity duration-300 ${
          isOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        onClick={onClose}
      />

      <div 
        className={`fixed inset-y-0 right-0 max-w-md w-full bg-white z-[70] shadow-2xl transform transition-transform duration-500 ease-out ${
          isOpen ? 'translate-x-0' : 'translate-x-full'
        }`}
      >
        <div className="flex flex-col h-full">
          <div className="flex items-center justify-between p-6 border-b border-gray-100">
            <h2 className="text-3xl font-bebas tracking-wide text-gray-900 flex items-center gap-3">
              YOUR CART
              <span className="text-sm bg-red-600 text-white px-3 py-1 rounded-full font-sans font-black">{totalItems}</span>
            </h2>
            <button onClick={onClose} className="text-gray-400 hover:text-red-600 transition-colors p-2 rounded-full hover:bg-gray-50">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-4">
                <ShoppingBag className="w-20 h-20 opacity-10" />
                <p className="text-xl font-bebas tracking-widest">EMPTY CART</p>
                <button 
                  onClick={onClose}
                  className="bg-red-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-500/20"
                >
                  BROWSE MENU
                </button>
              </div>
            ) : (
              <div className="space-y-8">
                <div className="space-y-4">
                    {items.map((item) => (
                    <div key={item.id} className="bg-white rounded-3xl p-4 flex gap-4 border border-gray-100 shadow-sm transition-all hover:shadow-md">
                        <div className="flex-1">
                          <h3 className="font-bold text-gray-900 text-base">{item.name}</h3>
                          {item.customDetails && (
                              <div className="mt-2 p-3 bg-gray-50 rounded-xl">
                                  <pre className="text-[10px] text-gray-500 font-sans whitespace-pre-wrap leading-tight">{item.customDetails}</pre>
                              </div>
                          )}
                          <p className="text-red-600 font-black text-lg mt-2 font-bebas tracking-wide">{item.price * item.quantity}/-</p>
                        </div>

                        <div className="flex flex-col items-end justify-between">
                          <button 
