                              <Trash2 className="w-4 h-4" />
                          </button>

                          <div className="flex items-center gap-4 bg-gray-50 rounded-2xl px-3 py-1.5 border border-gray-100">
                              <button 
                                onClick={() => onUpdateQuantity(item.id, -1)}
