interface NavbarProps {
  cartCount: number;
  onOpenCart: () => void;
  onNavigate: (view: 'home' | 'deals', hash?: string) => void;
  currentView: 'home' | 'deals';
}

export const Navbar: React.FC<NavbarProps> = ({ cartCount, onOpenCart, onNavigate, currentView }) => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const update = () => {
      const now = new Date();
      const pakDate = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Karachi" }));
      const h = pakDate.getHours();
      const d = pakDate.getDay();
      const openAt = 17;
      let open = false;
      let closeAt = (d === 1 || d === 6 || d === 0) ? 4 : 3;
      open = h < 5 ? h < closeAt : h >= openAt;
      setIsOpen(open);
    };
    update();
    const timer = setInterval(update, 60000);
    return () => clearInterval(timer);
  }, []);

  const links = [
    { name: 'MENU', hash: '#menu' },
    { name: 'DEALS', hash: '#deals' },
    { name: 'STORY', hash: '#about' },
  ];

  return (
    <nav className="fixed top-0 left-0 right-0 z-50 transition-all duration-300">
      <div className="absolute inset-0 bg-white/70 backdrop-blur-lg border-b border-gray-100"></div>

      <div className="container mx-auto max-w-7xl px-4 relative">
        <div className="flex items-center justify-between h-20 md:h-24">

          <a 
            href="#home" 
            onClick={(e) => { e.preventDefault(); onNavigate('home', '#home'); }}
            className="flex items-center gap-2 group"
          >
            <img src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/main/Logo.png" alt="L" className="h-10 md:h-14 drop-shadow-sm" />
            <div className="hidden sm:block">
              <span className="font-bebas text-2xl text-gray-900 leading-none block">MR. BEEF</span>
              <span className="text-[10px] font-black text-red-600 uppercase tracking-widest">Malir Legends</span>
            </div>
          </a>

          <div className="hidden md:flex items-center gap-8">
            {links.map((link) => (
              <a 
                key={link.name} 
                href={link.hash} 
                onClick={(e) => { 
                  e.preventDefault(); 
                  onNavigate(link.name === 'DEALS' ? 'deals' : 'home', link.hash); 
                }}
                className={`font-bebas text-xl tracking-widest transition-colors ${currentView === 'deals' && link.name === 'DEALS' ? 'text-red-600' : 'text-gray-500 hover:text-red-600'}`}
              >
                {link.name}
              </a>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <div className={`hidden sm:flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-black border tracking-widest transition-colors ${isOpen ? 'bg-green-50 border-green-100 text-green-600' : 'bg-red-50 border-red-100 text-red-600'}`}>
              <div className={`w-1.5 h-1.5 rounded-full ${isOpen ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
              {isOpen ? 'OPEN' : 'CLOSED'}
            </div>

            <button onClick={onOpenCart} className="relative p-3 bg-red-600 text-white rounded-2xl shadow-lg shadow-red-500/20 active:scale-95 transition-all">
              <ShoppingCart className="w-5 h-5" />
