export const Menu: React.FC<MenuProps> = ({ onAddToCart }) => {
  const categories = Array.from(new Set(MENU_ITEMS.map(item => item.category)));

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
        const offset = 180; 
        const bodyRect = document.body.getBoundingClientRect().top;
        const elementRect = element.getBoundingClientRect().top;
        const elementPosition = elementRect - bodyRect;
        const offsetPosition = elementPosition - offset;

        window.scrollTo({
            top: offsetPosition,
            behavior: 'smooth'
        });
    }
  };

  const getContainerId = (category: string) => {
      if (category === 'Chicken Broast') return 'sec-broast';
      if (category === 'Snacks') return 'sec-snacks';
      if (category.includes('Fries')) return 'sec-fries';
      if (category === 'Drinks') return 'sec-drinks';
      if (category === 'Add-ons') return 'sec-addons';
      return undefined;
  };

  const getSubcategorySectionId = (category: string, subcategory: string) => {
      if (category === 'House of Beef') {
          if (subcategory.includes('Classic')) return 'sec-classic-beef';
          if (subcategory.includes('Premium')) return 'sec-premium-beef';
      }
      if (category === 'House of Chicken') {
           return 'sec-chicken';
      }
      return undefined;
  };

  return (
    <section id="menu" className="pb-20 pt-10 scroll-mt-20">
      <div className="container mx-auto px-4 text-center mb-16 reveal">
        <h2 className="font-bebas text-6xl sm:text-8xl text-gray-900 tracking-wider mb-2">
          EXPLORE OUR <span className="text-orange-500">LEGENDARY</span> MENU
        </h2>
        <p className="font-cursive text-orange-600 text-2xl opacity-90 underline decoration-yellow-400 decoration-4 underline-offset-4">Juicy, flavorful, and made fresh for you.</p>
      </div>

      {/* Navigation - Bright & Sticky */}
      <div className="sticky top-[112px] md:top-24 z-40 bg-white/90 backdrop-blur-xl border-y border-orange-100 mb-16 py-4 shadow-sm">
        <div className="max-w-7xl mx-auto flex items-center gap-4 px-4 overflow-x-auto no-scrollbar scroll-smooth">
            {NAV_ITEMS.map((item, idx) => (
                <button
                    key={idx}
                    onClick={() => scrollToSection(item.targetId)}
                    className="flex flex-col items-center gap-2 min-w-[90px] group transition-all duration-300"
                >
                    <div className={`w-12 h-12 rounded-2xl border border-orange-100 flex items-center justify-center bg-orange-50 group-hover:bg-orange-600 group-hover:border-orange-600 transition-all duration-300 shadow-sm`}>
                        <item.icon className={`w-6 h-6 ${item.color} group-hover:text-white transition-colors`} />
                    </div>
                    <span className="text-[10px] font-black text-gray-400 group-hover:text-orange-600 uppercase tracking-widest transition-colors">
                        {item.label}
                    </span>
                </button>
            ))}
        </div>
      </div>

      <div className="container mx-auto px-4 max-w-7xl">
        <div className="space-y-24">
          {categories.map((category) => {
            const categoryItems = MENU_ITEMS.filter(item => item.category === category);
            const subcategories = Array.from(new Set(categoryItems.map(item => item.subcategory || 'General')));
            const containerIdVal = getContainerId(category);

            return (
              <div key={category} id={containerIdVal} className="reveal scroll-mt-32">
                <div className="flex items-center gap-4 mb-10">
                    <h3 className={`text-4xl sm:text-7xl font-bebas tracking-tighter uppercase text-gray-900`}>
                      {category}
                    </h3>
                    <div className="h-0.5 flex-1 bg-orange-100"></div>
                </div>

                {subcategories.map(subcategory => {
                  const items = categoryItems.filter(item => (item.subcategory || 'General') === subcategory);
                  const showSubheader = subcategory !== 'General';
                  const sectionId = !containerIdVal ? getSubcategorySectionId(category, subcategory) : undefined;

                  return (
                    <div key={subcategory} id={sectionId} className="mb-12 last:mb-0 scroll-mt-40">
                      {showSubheader && (
                        <h4 className="text-sm font-black text-gray-400 uppercase tracking-widest mb-6 flex items-center gap-3">
                          <span className="w-2 h-2 rounded-full bg-orange-500"></span>
                          {subcategory}
                        </h4>
                      )}

                      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6">
                        {items.map((item) => (
                          <div 
                            key={item.id}
                            onClick={() => onAddToCart(item)}
                            className={`group relative flex flex-col p-4 md:p-6 rounded-[2rem] bg-white border border-orange-100 shadow-sm hover:shadow-2xl hover:-translate-y-1 transition-all duration-300 cursor-pointer tap-highlight-transparent active:scale-95 overflow-hidden`}
                          >
                            {item.isPopular && (
                                <div className="absolute -top-1 -right-1 bg-orange-600 text-white text-[8px] md:text-[10px] font-black px-3 py-1 rounded-bl-2xl z-10 tracking-widest shadow-lg">
                                    POPULAR
                                </div>
                            )}

                            <div className="flex flex-col h-full relative z-10">
                              <h5 className="font-bebas text-xl md:text-3xl tracking-tight text-gray-900 mb-1 group-hover:text-orange-600 transition-colors leading-none">
                                {item.name}
                              </h5>

                              <p className="text-[10px] md:text-sm text-gray-400 leading-tight mb-4 flex-grow line-clamp-2">
                                {item.description}
                              </p>

                              <div className="flex justify-between items-center pt-3 border-t border-orange-50">
                                <span className="text-lg md:text-2xl font-bebas text-gray-900">
                                  {item.price}/-
                                </span>

                                <div className="w-8 h-8 md:w-10 md:h-10 rounded-xl bg-orange-50 text-orange-600 flex items-center justify-center group-hover:bg-orange-600 group-hover:text-white transition-all shadow-sm">
                                    <Plus className="w-4 h-4 md:w-6 md:h-6" />
