                                    TOP
                                </div>
                            )}

                            <div className="flex flex-col h-full relative z-10">
                              <h5 className="font-bebas text-lg md:text-3xl tracking-tight text-gray-900 mb-0.5 md:mb-1 group-hover:text-orange-600 transition-colors leading-none">
                                {item.name}
                              </h5>

                              <p className="text-[9px] md:text-sm text-gray-400 leading-tight mb-2 md:mb-4 flex-grow line-clamp-2 md:line-clamp-3">
                                {item.description}
                              </p>

                              <div className="flex justify-between items-center pt-2 md:pt-3 border-t border-orange-50">
                                <span className="text-base md:text-2xl font-bebas text-gray-900">
                                  {item.price}/-
                                </span>

                                <div className="w-6 h-6 md:w-10 md:h-10 rounded-lg md:rounded-xl bg-orange-50 text-orange-600 flex items-center justify-center group-hover:bg-orange-600 group-hover:text-white transition-all shadow-sm">
                                    <Plus className="w-3 h-3 md:w-6 md:h-6" />
                                </div>
                              </div>
                            </div>

                            {/* Decorative Corner */}
                            <div className="absolute -bottom-10 -right-10 w-24 h-24 bg-orange-500/5 rounded-full group-hover:scale-150 transition-transform duration-700"></div>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

