                <div className="container mx-auto px-4 max-w-6xl relative z-10">
                    <h2 className="font-bebas text-6xl sm:text-8xl text-center text-white mb-20 tracking-tighter reveal">
                        THE <span className="text-yellow-400 underline decoration-white/20 underline-offset-8">PROMISE</span> OF PURITY
                    </h2>
                    <div className="grid lg:grid-cols-2 gap-16 items-center">
                        <div className="relative group reveal">
                            <div className="absolute inset-0 bg-white/10 blur-[100px] rounded-full"></div>
                            <div className="relative bg-white/10 backdrop-blur-md p-8 rounded-[3.5rem] border border-white/20 shadow-2xl transition-transform duration-500">
                                <img src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/refs/heads/main/cow2.png" alt="Pure Beef" className="w-full h-auto drop-shadow-2xl" />
                                <div className="absolute bottom-10 left-0 right-0 text-center">
                                  <span className="font-bebas text-4xl text-white tracking-widest drop-shadow-md">100% PURE BEEF</span>
                                </div>
