const App: React.FC = () => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [currentView, setCurrentView] = useState<'home' | 'deals' | 'make-burger'>('home');
  const [optionModalOpen, setOptionModalOpen] = useState(false);
  const [currentOptionItem, setCurrentOptionItem] = useState<MenuItem | null>(null);
  const [currentOptions, setCurrentOptions] = useState<string[]>([]);
  const [modalSelectionMode, setModalSelectionMode] = useState<'single' | 'multiple'>('multiple');

  useEffect(() => {
    const handleScroll = () => setShowScrollTop(window.scrollY > 400);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavigate = (view: 'home' | 'deals', hash?: string) => {
    setCurrentView(view);
    if (view === 'home' && hash) {
        setTimeout(() => {
            const element = document.querySelector(hash);
            if (element) {
                const offset = 100;
                const pos = element.getBoundingClientRect().top + window.pageYOffset - offset;
                window.scrollTo({ top: pos, behavior: "smooth" });
            }
        }, 150);
    } else {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleAddToCartClick = (item: MenuItem) => {
    if (item.id === 'a5') {
        setCurrentOptionItem(item);
        setCurrentOptions(['Garlic', 'Chipotle', 'Toumiya', 'Honey Mustard', 'Hot Jalapeño', 'Barbecue', 'Chef\'s Signature']);
        setModalSelectionMode('multiple');
        setOptionModalOpen(true);
        return;
    }
    if (item.id === 'd1') {
        setCurrentOptionItem(item);
        setCurrentOptions(['7up', 'Pepsi']);
        setModalSelectionMode('multiple');
        setOptionModalOpen(true);
        return;
    }
    if (item.id === 'b2' || item.id === 'b3') {
        setCurrentOptionItem(item);
        setCurrentOptions(['Grilled Onion', 'Raw Onion']);
        setModalSelectionMode('single');
        setOptionModalOpen(true);
        return;
    }
    addToCart(item);
  };

  const handleOptionConfirm = (selections: { option: string; quantity: number }[]) => {
    if (!currentOptionItem) return;
    selections.forEach(sel => {
        const variantItem = { ...currentOptionItem, id: `${currentOptionItem.id}-${sel.option}`, name: `${currentOptionItem.name} (${sel.option})` };
        addToCart(variantItem, sel.quantity);
    });
  };

  const addToCart = (item: MenuItem, quantity: number = 1) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + quantity } : i);
      return [...prev, { ...item, quantity: quantity }];
    });
  };

  const totalItems = cartItems.reduce((acc, item) => acc + item.quantity, 0);
  const totalAmount = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  return (
    <div className="min-h-screen text-gray-900 flex flex-col relative bg-[#fff9f5]">
      {currentView !== 'make-burger' && (
          <Navbar 
            cartCount={totalItems} 
            onOpenCart={() => setIsCartOpen(true)}
            onNavigate={handleNavigate}
            currentView={currentView === 'deals' ? 'deals' : 'home'}
          />
      )}

      <Cart 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cartItems} 
        onRemove={(id) => setCartItems(prev => prev.filter(i => i.id !== id))}
        onUpdateQuantity={(id, delta) => setCartItems(prev => prev.map(i => i.id === id ? { ...i, quantity: Math.max(1, i.quantity + delta) } : i))}
      />

      <OptionModal 
        isOpen={optionModalOpen}
        onClose={() => setOptionModalOpen(false)}
        item={currentOptionItem}
        options={currentOptions}
        selectionType={modalSelectionMode}
        onConfirm={handleOptionConfirm}
      />

      <main className="flex-grow">
        {currentView === 'home' ? (
          <>
            <Hero />
            <Menu onAddToCart={handleAddToCartClick} />

            <section id="about" className="py-24 bg-orange-600 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-yellow-400 opacity-20 blur-[100px] rounded-full"></div>
                <div className="container mx-auto px-4 max-w-6xl relative z-10">
                    <h2 className="font-bebas text-6xl sm:text-8xl text-center text-white mb-20 tracking-tighter reveal">
                        THE <span className="text-yellow-400 underline decoration-white/20 underline-offset-8">PROMISE</span> OF PURITY
                    </h2>
                    <div className="grid lg:grid-cols-2 gap-16 items-center">
                        <div className="relative group reveal">
                            <div className="absolute inset-0 bg-white/10 blur-[100px] rounded-full"></div>
                            <div className="relative bg-white/10 backdrop-blur-md p-8 rounded-[3.5rem] border border-white/20 shadow-2xl transition-transform duration-500">
                                <img src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/refs/heads/main/cow2.png" alt="Pure Beef" className="w-full h-auto drop-shadow-2xl" />
                                <div className="absolute bottom-10 left-0 right-0 text-center">
                                  <span className="font-bebas text-4xl text-white tracking-widest drop-shadow-md">100% PURE BEEF</span>
                                </div>
                            </div>
                        </div>
                        <div className="space-y-10 reveal">
                            <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl space-y-6">
                                <p className="font-cursive text-3xl text-orange-600 leading-tight">
                                    "Bringing authentic, premium smash burgers to the people of Karachi."
                                </p>
                                <p className="text-gray-600 text-lg leading-relaxed">
                                    We believe great food starts with passion and ends with satisfaction. Our team focuses on maintaining premium standards, hygiene, and freshness in every single order.
                                </p>
                                <div className="pt-8 border-t border-gray-100 flex gap-10 items-center">
                                  <div className="text-center">
                                    <span className="block text-4xl font-bebas text-orange-600">80/20</span>
                                    <span className="text-xs text-gray-400 font-bold tracking-widest uppercase">Ratio</span>
                                  </div>
                                  <div className="text-center">
                                    <span className="block text-4xl font-bebas text-yellow-600">FRESH</span>
                                    <span className="text-xs text-gray-400 font-bold tracking-widest uppercase">Grind</span>
                                  </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            <GoogleReviews />
            <LiveMap />
          </>
        ) : currentView === 'deals' ? (
          <Deals onBack={() => handleNavigate('home')} />
        ) : (
            <MakeYourBurger onBack={() => handleNavigate('home')} onAddToCart={addToCart} />
        )}
      </main>

      {currentView !== 'make-burger' && (
      <footer id="contact" className="bg-gray-900 text-white pt-24 pb-12 mt-auto">
         <div className="container mx-auto px-6 max-w-7xl">
             <div className="grid lg:grid-cols-2 gap-16 mb-20">
                 <div className="space-y-8 text-center lg:text-left">
                     <h3 className="font-bebas text-6xl text-white tracking-tighter leading-none uppercase">
                        MR. BEEF BURGRZ
                     </h3>
                     <p className="text-gray-400 text-xl max-w-md mx-auto lg:mx-0">Juicy smash burgers, crispy chicken, and loaded fries. <br/> <span className="text-yellow-500 font-bold">#KarachiSpecial</span></p>

                     <div className="flex gap-4 justify-center lg:justify-start">
                        {[Instagram, Facebook, Youtube, TikTokIcon, Linkedin].map((Icon, i) => (
                            <a key={i} href="#" className="w-12 h-12 rounded-xl bg-white/5 flex items-center justify-center hover:bg-orange-600 hover:text-white transition-all duration-300 transform hover:-translate-y-2">
                                <Icon className="w-6 h-6" />
                            </a>
                        ))}
                     </div>
                 </div>

