interface NavbarProps {
  cartCount: number;
  onOpenCart: () => void;
  onNavigate: (view: 'home' | 'deals', hash?: string) => void;
  currentView: 'home' | 'deals';
}

export const Navbar: React.FC<NavbarProps> = ({ cartCount, onOpenCart, onNavigate, currentView }) => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const updateStatus = () => {
      const now = new Date();
      const pakistanTimeStr = now.toLocaleString("en-US", { timeZone: "Asia/Karachi" });
      const pakistanDate = new Date(pakistanTimeStr);
      const hour = pakistanDate.getHours();
      const day = pakistanDate.getDay();
      const openHour = 17;
      let isShopOpen = false;
      let closingTime = (day === 1 || day === 6 || day === 0) ? 4 : 3;

      if (hour < 5) {
        isShopOpen = hour < closingTime;
      } else {
        isShopOpen = hour >= openHour;
      }
      setIsOpen(isShopOpen);
    };

    updateStatus();
    const interval = setInterval(updateStatus, 60000);
    return () => clearInterval(interval);
  }, []);

  const navLinks = [
    { name: 'MENU', href: '#menu', view: 'home' },
    { name: 'DEALS', href: '#', view: 'deals' },
    { name: 'ABOUT', href: '#about', view: 'home' },
    { name: 'CONTACT', href: '#contact', view: 'home' },
  ];

  const handleLinkClick = (e: React.MouseEvent, link: typeof navLinks[0]) => {
      e.preventDefault();
      onNavigate(link.view as 'home' | 'deals', link.href !== '#' ? link.href : undefined);
  };

  return (
    <nav className="sticky top-0 z-50 transition-all duration-300 border-b border-orange-100 bg-white/80 backdrop-blur-xl">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row md:items-center justify-between h-auto py-2 md:h-24">

          <div className="flex items-center justify-between md:justify-start w-full md:w-auto h-full gap-4">
            <a 
              href="#home" 
              onClick={(e) => { e.preventDefault(); onNavigate('home', '#home'); }}
              className="flex-shrink-0 flex items-center group"
            >
              <img 
                src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/main/Logo.png" 
                alt="Logo" 
                className="h-12 md:h-16 w-auto drop-shadow-sm" 
              />
              <div className="flex flex-col ml-3 border-l border-orange-100 pl-3">
                <span className="font-bebas text-xl md:text-2xl tracking-tighter text-gray-900 leading-none uppercase">MR. BEEF BURGRZ</span>
                <span className="font-cursive text-orange-600 text-[10px] md:text-sm">Juicy to the last bite!</span>
              </div>
            </a>

            <div className="flex md:hidden items-center gap-2">
              <div className={`flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold tracking-tighter border transition-all duration-500 ${isOpen ? 'bg-green-500/10 border-green-500/30 text-green-600' : 'bg-red-500/10 border-red-500/30 text-red-600'}`}>
                <span className={`w-1 h-1 rounded-full ${isOpen ? 'bg-green-500' : 'bg-red-500'}`}></span>
                {isOpen ? 'OPEN' : 'CLOSED'}
              </div>
              <button onClick={onOpenCart} className="relative p-2 text-gray-900 bg-white rounded-lg border border-orange-100">
                <ShoppingCart className="w-5 h-5" />
                {cartCount > 0 && (
                  <span className="absolute -top-1.5 -right-1.5 bg-orange-600 text-white text-[10px] font-black w-4 h-4 flex items-center justify-center rounded-full">
                    {cartCount}
                  </span>
                )}
              </button>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-8">
            <div className="flex items-center gap-8 border-r border-orange-100 pr-8">
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  onClick={(e) => handleLinkClick(e, link)}
                  className={`relative font-bebas text-xl tracking-widest transition-colors duration-300 group ${
                    currentView === 'deals' && link.name === 'DEALS' 
                      ? 'text-orange-600' 
                      : 'text-gray-500 hover:text-orange-600'
                  }`}
                >
                  {link.name}
                  <span className={`absolute -bottom-1 left-0 h-0.5 bg-orange-500 transition-all duration-300 ${currentView === 'deals' && link.name === 'DEALS' ? 'w-full' : 'w-0 group-hover:w-full'}`}></span>
                </a>
              ))}
            </div>

            <div className="flex items-center gap-4">
              <button
                onClick={onOpenCart}
                className="relative group flex items-center gap-3 bg-orange-600 hover:bg-orange-700 text-white px-6 py-3 rounded-xl font-bold transition-all duration-300 shadow-lg shadow-orange-500/20 active:scale-95"
              >
                <ShoppingCart className="w-5 h-5" />
                <span className="tracking-widest font-bebas text-lg uppercase">CART</span>
                {cartCount > 0 && (
                  <span className="bg-white text-orange-600 text-xs font-black px-2 py-0.5 rounded-full">
                    {cartCount}
                  </span>
                )}
              </button>

              <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border transition-all duration-500 ${isOpen ? 'bg-green-500/10 border-green-500/30 text-green-600' : 'bg-red-500/10 border-red-500/30 text-red-600'}`}>
