      </main>

      {currentView !== 'make-burger' && (
      <footer id="contact" className="bg-[#1a0f0a] text-white pt-24 pb-12 mt-auto">
         <div className="container mx-auto px-6 max-w-7xl">
             <div className="grid lg:grid-cols-2 gap-16 mb-20">
                 <div className="space-y-8 text-center lg:text-left">
                     <h3 className="font-bebas text-6xl text-white tracking-tighter leading-none uppercase">
