const GoogleReviews = () => {
  const [loading, setLoading] = useState(true);
  const [reviews, setReviews] = useState<{name: string; text: string; stars: number; source?: string}[]>([]);
  const [error, setError] = useState(false);

  const fetchLiveReviews = async () => {
    setLoading(true);
    setError(false);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: "Summarize the latest 5-star customer reviews for Mr. Beef Burgrz in Malir, Karachi. Mention key highlights and names if available.",
        config: {
          tools: [{googleMaps: {}}],
          toolConfig: {
            retrievalConfig: {
              latLng: {
                latitude: 24.902723,
                longitude: 67.1839976
              }
            }
          }
        },
      });

      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const reviewSnippets = response.candidates?.[0]?.groundingMetadata?.searchEntryPoint?.renderedContent;

      // Extract specific review snippets from maps tool if available
      const liveData = chunks?.filter(c => c.maps)?.map(c => ({
        name: c.maps.title || "Happy Customer",
        text: c.maps.placeAnswerSources?.[0]?.reviewSnippets?.[0] || response.text || "Authentic and juicy burgers.",
        stars: 5,
        source: c.maps.uri
      })) || [];

      if (liveData.length > 0) {
        setReviews(liveData);
      } else {
        // Fallback to parsed AI text if chunks are missing but text exists
        setReviews([{
          name: "Latest Review",
          text: response.text || "The best beef burgers in Malir!",
          stars: 5
        }]);
      }
    } catch (err) {
      console.error("Failed to fetch live reviews:", err);
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLiveReviews();
  }, []);

  return (
    <section id="reviews" className="py-24 bg-white relative overflow-hidden">
      <div className="container mx-auto px-4 max-w-6xl">
