               <div className="flex text-yellow-500">
                  {[...Array(5)].map((_, i) => <Star key={i} size={20} fill="currentColor" />)}
               </div>
               <span className="text-sm font-black text-gray-400 tracking-widest uppercase flex items-center gap-2">
                 {loading ? 'SYNCING WITH GOOGLE...' : 'DIRECT FROM GOOGLE MAPS'}
                 {!loading && <button onClick={fetchLiveReviews} className="p-1 hover:text-orange-600 transition-colors"><RefreshCw size={14} /></button>}
               </span>
            </div>
          </div>
          <a href={GOOGLE_MAPS_LINK} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 text-orange-600 font-bold hover:underline group font-inter">
            View on Google Maps <ExternalLink size={16} className="group-hover:translate-x-1 transition-transform" />
          </a>
        </div>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 gap-4 opacity-50">
             <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="font-bebas text-2xl tracking-widest animate-pulse">CONNECTING TO GOOGLE BUSINESS...</p>
          </div>
        ) : (
