          <div className="flex items-center justify-between md:justify-start w-full md:w-auto h-full gap-4">
            <a 
              href="#home" 
              onClick={(e) => { e.preventDefault(); onNavigate('home', '#home'); }}
              className="flex-shrink-0 flex items-center group py-2"
            >
              <img 
                src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/main/Logo.png" 
                alt="Logo" 
                className="h-10 md:h-16 w-auto drop-shadow-sm brightness-110" 
              />
              <div className="flex flex-col ml-3 border-l-2 border-white/10 pl-3">
                <span className="font-bebas text-xl md:text-2xl tracking-tighter text-orange-500 leading-none uppercase">MR. BEEF BURGRZ</span>
                <span className="font-cursive text-gray-400 text-[11px] md:text-sm whitespace-nowrap">Juicy to the last bite!</span>
              </div>
            </a>

            <div className="flex md:hidden items-center gap-2">
              <div className={`flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold tracking-tighter border transition-all duration-500 ${isOpen ? 'bg-green-500/10 border-green-500/30 text-green-500' : 'bg-red-500/10 border-red-500/30 text-red-500'}`}>
                <span className={`w-1 h-1 rounded-full ${isOpen ? 'bg-green-500' : 'bg-red-500'}`}></span>
                {isOpen ? 'OPEN' : 'CLOSED'}
              </div>
              <button onClick={onOpenCart} className="relative p-2 text-white bg-white/5 rounded-lg border border-white/10 hover:bg-white/10 transition-colors">
