        </div>

        {/* Back: Hours */}
        <div className={`absolute inset-0 backface-hidden rotate-y-180 flex items-center justify-center rounded-xl border border-white/20 bg-gradient-to-br from-orange-500 to-orange-600 text-white shadow-2xl px-2`}>
          <div className="flex flex-col items-center justify-center leading-[1.1] text-center">
             <span className={`${mobile ? "text-[8px]" : "text-[11px]"} font-black tracking-tight text-white uppercase`}>Mon-Thu 5PM - 3AM</span>
             <span className={`${mobile ? "text-[8px]" : "text-[11px]"} font-black tracking-tight text-white uppercase`}>Fri-Sun 5PM - 4AM</span>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 border-b ${
      isScrolled 
        ? 'bg-neutral-950/60 backdrop-blur-2xl border-white/5 py-2' 
