              >
                <ChevronLeft size={20} />
              </button>
            )}

            <div 
              ref={scrollRef}
              onScroll={checkScroll}
              className="flex items-center gap-4 overflow-x-auto no-scrollbar scroll-smooth justify-start md:justify-center"
            >
                {NAV_ITEMS.map((item, idx) => (
                    <button
